// Access the list of results
const results = $input.first().json.final_results;

// Function to clean AI text for Slack's specific Markdown
const cleanForSlack = (text) => {
  return text
    .replace(/\*\*(.*?)\*\*/g, '*$1*') // Convert **bold** to *bold*
    .replace(/^>\s*-?\s*/gm, '• ')     // Convert AI quotes/bullets to clean dots
    .replace(/\n{3,}/g, '\n\n');      // Remove excessive empty lines
};

// Format each report with a nice header and divider
const formattedReports = results.map((res, i) => {
  const cleanedText = cleanForSlack(res.formatted_output);
  return `${cleanedText}`;
});

// Join everything into one giant message
const finalBody = `*WEEKLY CONTENT SUMMARY REPORT*\n` + 
                  `━`.repeat(15) + `\n\n` + 
                  formattedReports.join('\n\n' + `━`.repeat(15) + `\n\n`);

return { final_text: finalBody };
